PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "role" varchar not null default 'user', "pin" varchar, "is_active" tinyint(1) not null default '1', "last_login_at" datetime, "last_login_ip" varchar);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "account_balances" ("id" integer primary key autoincrement not null, "user_id" integer not null, "principal_amount" numeric not null default '0', "current_balance" numeric not null default '0', "last_growth_applied_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "deposits" ("id" integer primary key autoincrement not null, "user_id" integer not null, "tx_hash" varchar, "amount_btc" numeric not null, "amount_usd" numeric not null, "status" varchar not null default 'pending', "notes" text, "confirmed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "roi_settings" ("id" integer primary key autoincrement not null, "user_id" integer, "scope" varchar not null default 'global', "daily_rate_percent" numeric not null, "active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "transaction_logs" ("id" integer primary key autoincrement not null, "user_id" integer not null, "type" varchar not null, "amount" numeric not null, "balance_after" numeric not null, "meta" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "audit_logs" ("id" integer primary key autoincrement not null, "admin_id" integer, "action" varchar not null, "target_type" varchar, "target_id" varchar, "details" text, "created_at" datetime, "updated_at" datetime, foreign key("admin_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "withdrawal_requests" ("id" integer primary key autoincrement not null, "user_id" integer not null, "amount" numeric not null, "btc_address" varchar not null, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "admin_notes" text, "processed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "email_verification_codes" ("id" integer primary key autoincrement not null, "email" varchar not null, "code" varchar not null, "expires_at" datetime not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "user_notifications" ("id" integer primary key autoincrement not null, "user_id" integer, "title" varchar not null, "message" text not null, "type" varchar check ("type" in ('info', 'success', 'warning')) not null default 'info', "is_read" tinyint(1) not null default '0', "sent_by" integer, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("sent_by") references "users"("id") on delete set null);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE INDEX "email_verification_codes_email_index" on "email_verification_codes" ("email");
COMMIT;
